packages/db/src/schema/model-profiles.ts.content:
/**
 * Model Profiles - профили моделей с верификацией и рейтингом
 * Updated for MVP: Create Model Card functionality
 */

import { pgTable, uuid, varchar, decimal, integer, jsonb, boolean, timestamp, index, uniqueIndex, text } from 'drizzle-orm/pg-core';
import { relations } from 'drizzle-orm';
import { users } from './users';

export const modelProfiles = pgTable(
  'model_profiles',
  {
    id: uuid('id').defaultRandom().primaryKey(),
    userId: uuid('user_id').references(() => users.id, { onDelete: 'cascade' }),
    managerId: uuid('manager_id').references(() => users.id),

    // Basic info
    displayName: varchar('display_name', { length: 100 }).notNull(),
    slug: varchar('slug', { length: 100 }).unique(),
    biography: text('biography'), // Short bio/description

    // Verification
    verificationStatus: varchar('verification_status', { length: 30 })
      .$type<'pending' | 'video_required' | 'document_required' | 'verified' | 'rejected'>()
      .default('pending'),
    verificationCompletedAt: timestamp('verification_completed_at'),
    lastVideoVerification: timestamp('last_video_verification'),
    eliteStatus: boolean('elite_status').default(false),

    // Pricing
    rateHourly: decimal('rate_hourly', { precision: 10, scale: 2 }),
    rateOvernight: decimal('rate_overnight', { precision: 10, scale: 2 }),

    // Availability
    availabilityStatus: varchar('availability_status', { length: 30 })
      .$type<'offline' | 'online' | 'in_shift' | 'busy'>()
      .default('offline'),
    nextAvailableAt: timestamp('next_available_at'),

    // Attributes (JSONB for flexibility)
    psychotypeTags: jsonb('psychotype_tags').$type<string[]>(),
    languages: jsonb('languages').$type<string[]>(),

    physicalAttributes: jsonb('physical_attributes').$type<{
      age?: number;
      height?: number;
      weight?: number;
      bustSize?: number;
      bustType?: 'natural' | 'silicone';
      bodyType?: 'slim' | 'curvy' | 'bbw' | 'pear' | 'fit';
      temperament?: 'gentle' | 'active' | 'adaptable';
      sexuality?: 'active' | 'passive' | 'universal';
      hairColor?: string;
      eyeColor?: string;
    }>(),

    // Stats
    ratingReliability: decimal('rating_reliability', { precision: 3, scale: 2 }).default('0.00'),
    totalMeetings: integer('total_meetings').default(0),
    totalCancellations: integer('total_cancellations').default(0),
    cancellationsLast3Months: integer('cancellations_last_3_months').default(0),

    // Media
    photoCount: integer('photo_count').default(0),
    videoWalkthroughUrl: varchar('video_walkthrough_url', { length: 500 }),
    videoVerificationUrl: varchar('video_verification_url', { length: 500 }),
    mainPhotoUrl: varchar('main_photo_url', { length: 500 }), // Primary photo for display

    // Publication
    isPublished: boolean('is_published').default(false),
    publishedAt: timestamp('published_at'),

    // Timestamps
    createdAt: timestamp('created_at').defaultNow().notNull(),
    updatedAt: timestamp('updated_at').defaultNow().notNull(),
  },
  (table) => ({
    userIdIdx: uniqueIndex('model_user_unique').on(table.userId),
    managerIdx: index('model_manager_idx').on(table.managerId),
    slugIdx: uniqueIndex('model_slug_unique').on(table.slug),
    statusIdx: index('model_status_idx').on(table.availabilityStatus),
    eliteIdx: index('model_elite_idx').on(table.eliteStatus),
    verificationIdx: index('model_verification_idx').on(table.verificationStatus),
    publishedIdx: index('model_published_idx').on(table.isPublished),
  })
);

export const modelProfilesRelations = relations(modelProfiles, ({ one, many }) => ({
  user: one(users, {
    fields: [modelProfiles.userId],
    references: [users.id],
  }),
  manager: one(users, {
    fields: [modelProfiles.managerId],
    references: [users.id],
  }),
  bookings: many(bookings),
  reviews: many(reviews),
  mediaFiles: many(mediaFiles),
}));

// Type exports
export type ModelProfile = typeof modelProfiles.$inferSelect;
export type NewModelProfile = typeof modelProfiles.$inferInsert;

// Forward imports for relations
import { bookings } from './bookings';
import { reviews } from './reviews';
import { mediaFiles } from './media';

packages/db/src/schema/media.ts.content:
/**
 * Media Files - файлы (фото, видео) - ссылки на MinIO
 * Updated for MVP: Presigned URL support + sortOrder
 */

import { pgTable, uuid, varchar, integer, timestamp, jsonb, boolean, index, uniqueIndex } from 'drizzle-orm/pg-core';
import { relations } from 'drizzle-orm';
import { users } from './users';
import { modelProfiles } from './model-profiles';

export const mediaFiles = pgTable(
  'media_files',
  {
    id: uuid('id').defaultRandom().primaryKey(),

    ownerId: uuid('owner_id').references(() => users.id, { onDelete: 'cascade' }).notNull(),
    modelId: uuid('model_id').references(() => modelProfiles.id, { onDelete: 'cascade' }),

    fileType: varchar('file_type', { length: 20 }).$type<'photo' | 'video' | 'document'>().notNull(),
    mimeType: varchar('mime_type', { length: 100 }).notNull(),
    fileSize: integer('file_size'),

    // Storage
    storageKey: varchar('storage_key', { length: 500 }).notNull().unique(), // MinIO object key
    bucket: varchar('bucket', { length: 100 }).default('escort-media'),
    cdnUrl: varchar('cdn_url', { length: 500 }),
    presignedUrl: varchar('presigned_url', { length: 1000 }), // Temporary upload URL
    presignedExpiresAt: timestamp('presigned_expires_at'),

    // Ordering
    sortOrder: integer('sort_order').default(0),

    // Visibility Control (for public profile display)
    isPublicVisible: boolean('is_public_visible').default(true), // Toggle show/hide on public profile
    albumCategory: varchar('album_category', { length: 50 }).default('portfolio'), // portfolio, vip, elite, verified

    // Verification
    isVerified: boolean('is_verified').default(false),
    verificationDate: timestamp('verification_date'),

    // Metadata
    metadata: jsonb('metadata').$type<{
      width?: number;
      height?: number;
      duration?: number;
      uploadedFrom?: string; // IP or device info
      originalName?: string;
    }>(),

    // Moderation
    moderationStatus: varchar('moderation_status', { length: 20 }).$type<'pending' | 'approved' | 'rejected'>().default('pending'),
    moderationReason: varchar('moderation_reason', { length: 500 }),
    moderatedBy: uuid('moderated_by').references(() => users.id),
    moderatedAt: timestamp('moderated_at'),

    // Timestamps
    createdAt: timestamp('created_at').defaultNow().notNull(),
    updatedAt: timestamp('updated_at').defaultNow().notNull(),
  },
  (table) => ({
    ownerIdx: index('media_owner_idx').on(table.ownerId),
    modelIdx: index('media_model_idx').on(table.modelId),
    typeIdx: index('media_type_idx').on(table.fileType),
    verifiedIdx: index('media_verified_idx').on(table.isVerified),
    moderationIdx: index('media_moderation_idx').on(table.moderationStatus),
    storageKeyIdx: uniqueIndex('media_storage_key_unique').on(table.storageKey),
  })
);

export const mediaFilesRelations = relations(mediaFiles, ({ one }) => ({
  owner: one(users, {
    fields: [mediaFiles.ownerId],
    references: [users.id],
  }),
  model: one(modelProfiles, {
    fields: [mediaFiles.modelId],
    references: [modelProfiles.id],
  }),
}));

// Type exports
export type MediaFile = typeof mediaFiles.$inferSelect;
export type NewMediaFile = typeof mediaFiles.$inferInsert;

apps/api/src/app.module.ts.content:
/**
 * Корневой модуль NestJS: подключает конфиг, БД, доменные модули и ограничение частоты запросов.
 *
 * Порядок загрузки: ConfigModule (читает .env из корня репозитория) → DatabaseModule (провайдер DRIZZLE)
 * → модули с контроллерами (HTTP-маршруты вешаются на приложение в main.ts).
 *
 * Поток запроса: HTTP → Controller → Service → @Inject('DRIZZLE') → PostgreSQL;
 * файлы профилей: Profiles/Media → presigned URL → клиент грузит в MinIO → confirm → снова API/БД.
 *
 * Карта проекта: docs/CODEBASE_GUIDE.md
 */

import { Module } from '@nestjs/common';
import { ConfigModule } from '@nestjs/config';
import { DatabaseModule } from './database/database.module';
import { HealthModule } from './health/health.module';
import { UsersModule } from './users/users.module';
import { AuthModule } from './auth/auth.module';
import { ModelsModule } from './models/models.module';
import { ClientsModule } from './clients/clients.module';
import { BookingsModule } from './bookings/bookings.module';
import { EscrowModule } from './escrow/escrow.module';
import { ReviewsModule } from './reviews/reviews.module';
import { BlacklistModule } from './blacklist/blacklist.module';
import { MediaModule } from './media/media.module';
import { ProfilesModule } from './profiles/profiles.module';

// Security modules
import { AuthGuardsModule } from './auth/guards/auth-guards.module';
import { RateLimitModule } from './security/rate-limit.config';

@Module({
  imports: [
    ConfigModule.forRoot({
      isGlobal: true,
      envFilePath: '../../.env',
    }),
    DatabaseModule,
    HealthModule,
    UsersModule,
    AuthModule,
    AuthGuardsModule,
    RateLimitModule,
    ModelsModule,
    ClientsModule,
    BookingsModule,
    EscrowModule,
    ReviewsModule,
    BlacklistModule,
    MediaModule,
    ProfilesModule,
  ],
})
export class AppModule {}

apps/api/src/main.ts.content:
/**
 * Escort Platform API - Main Entry Point
 * 
 * Production-grade security hardening:
 * - Environment validation at startup
 * - Helmet security headers (CSP, HSTS, XSS protection)
 * - CORS with multiple allowed origins
 * - Global validation pipe with sanitization
 * - Rate limiting (via RateLimitModule)
 * - JWT authentication (via AuthGuardsModule)
 * - Audit logging (via AuditLogger)
 * 
 * Карта модулей и данных: docs/CODEBASE_GUIDE.md
 */

import 'reflect-metadata';
import { NestFactory } from '@nestjs/core';
import {
  ValidationPipe,
  Catch,
  ExceptionFilter,
  ArgumentsHost,
  Logger,
  VersioningType,
  BadRequestException,
} from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { SwaggerModule, DocumentBuilder } from '@nestjs/swagger';
import { AppModule } from './app.module';
import { Response, Request } from 'express';
import { validateEnv } from './config/validation.schema';
import { getHelmetConfig } from './security/helmet.config';

/**
 * Global Exception Filter with enhanced logging
 */
@Catch()
export class GlobalExceptionFilter implements ExceptionFilter {
  private readonly logger = new Logger('Exceptions');

  catch(exception: any, host: ArgumentsHost) {
    const ctx = host.switchToHttp();
    const response = ctx.getResponse<Response>();
    const request = ctx.getRequest<Request>();

    const isDev = process.env.NODE_ENV === 'development';

    // Log error details
    this.logger.error({
      message: exception?.message,
      stack: exception?.stack,
      url: request?.url,
      method: request?.method,
      ip: request?.ip,
      userAgent: request?.headers['user-agent'],
      timestamp: new Date().toISOString(),
    });

    // Don't expose internal errors in production
    response.status(exception?.status || 500).json({
      statusCode: exception?.status || 500,
      message: exception?.message || 'Internal server error',
      ...(isDev && { stack: exception?.stack }),
      ...(isDev && { error: exception?.name }),
    });
  }
}

async function bootstrap() {
  const logger = new Logger('Bootstrap');

  // ============================================
  // ENVIRONMENT VALIDATION
  // ============================================
  logger.log('Validating environment variables...');
  const envConfig = validateEnv(process.env);
  logger.log(`✓ Environment validated (NODE_ENV: ${envConfig.NODE_ENV})`);

  // ============================================
  // APP INITIALIZATION
  // ============================================
  const app = await NestFactory.create(AppModule, {
    logger: ['error', 'warn', 'log', 'debug', 'verbose'],
    snapshot: process.env.NODE_ENV === 'development', // Debug mode
  });

  const configService = app.get(ConfigService);

  // ============================================
  // GLOBAL EXCEPTION FILTER
  // ============================================
  app.useGlobalFilters(new GlobalExceptionFilter());

  // ============================================
  // SECURITY HEADERS (HELMET)
  // ============================================
  app.use(getHelmetConfig(configService));
  logger.log('✓ Helmet security headers enabled');

  // ============================================
  // CORS CONFIGURATION
  // ============================================
  const allowedOrigins = [
    envConfig.FRONTEND_URL,
    ...(envConfig.ALLOWED_ORIGINS || '').split(',').map((url) => url.trim()).filter(Boolean),
  ].filter(Boolean);

  app.enableCors({
    origin: (origin, callback) => {
      // Allow requests with no origin (mobile apps, Postman, etc.)
      if (!origin) return callback(null, true);

      if (allowedOrigins.includes(origin)) {
        callback(null, true);
      } else {
        logger.warn(`Blocked CORS request from: ${origin}`);
        callback(new Error('Not allowed by CORS'));
      }
    },
    credentials: true,
    methods: ['GET', 'POST', 'PUT', 'DELETE', 'PATCH', 'OPTIONS'],
    allowedHeaders: ['Content-Type', 'Authorization', 'X-Requested-With', 'X-Request-ID'],
    exposedHeaders: ['X-Request-Id', 'X-RateLimit-Limit', 'X-RateLimit-Remaining'],
    maxAge: 86400, // 24 hours
  });
  logger.log(`✓ CORS enabled for: ${allowedOrigins.join(', ')}`);

  // ============================================
  // API VERSIONING - DISABLED FOR AUTH COMPATIBILITY
  // ============================================
  /*
  app.enableVersioning({
    type: VersioningType.URI,
    defaultVersion: '1',
    prefix: 'v',
  });
  logger.log('✓ API versioning enabled (v1)');
  */
  logger.log('⚠️  API versioning disabled for auth compatibility');

  // ============================================
  // FAVICON
  // ============================================
  app.use('/favicon.ico', (req: any, res: any) => {
    res.status(204).send();
  });

  // ============================================
  // GLOBAL VALIDATION PIPE - ENABLED
  // ============================================
  app.useGlobalPipes(
    new ValidationPipe({
      whitelist: true,
      forbidNonWhitelisted: false,
      transform: true,
      transformOptions: {
        enableImplicitConversion: true,
      },
      disableErrorMessages: envConfig.NODE_ENV === 'production',
      exceptionFactory: (errors) => {
        const formatted = errors.map((e) => ({
          field: e.property,
          errors: Object.values(e.constraints || {}),
        }));
        return new BadRequestException({
          message: 'Validation failed',
          errors: formatted,
        });
      },
    }),
  );
  logger.log('✓ Global validation pipe enabled');

  // ============================================
  // SWAGGER API DOCUMENTATION
  // ============================================
  const config = new DocumentBuilder()
    .setTitle('Lovnge Platform API')
    .setDescription('Premium escort platform API documentation')
    .setVersion('1.0')
    .addBearerAuth({
      description: 'JWT token obtained from /auth/login',
      name: 'Authorization',
      bearerFormat: 'Bearer',
      scheme: 'Bearer',
      type: 'http',
      in: 'Header',
    })
    .addTag('auth', 'Authentication endpoints')
    .addTag('profiles', 'Model profile management')
    .addTag('bookings', 'Booking management')
    .addTag('escrow', 'Escrow payments')
    .addTag('users', 'User management')
    .build();

  const document = SwaggerModule.createDocument(app, config);
  SwaggerModule.setup('api/docs', app, document, {
    swaggerOptions: {
      persistAuthorization: true,
      displayRequestDuration: true,
      filter: true,
    },
    customCss: '.swagger-ui .topbar { display: none }',
    customSiteTitle: 'Lovnge API Docs',
  });
  logger.log('✓ Swagger documentation enabled at /api/docs');

  // ============================================
  // GRACEFUL SHUTDOWN
  // ============================================
  const shutdownSignal = async (signal: string) => {
    logger.log(`Received ${signal}, starting graceful shutdown...`);

    // Close server connections
    await app.close();

    // TODO: Close database connections
    // TODO: Flush audit logs
    // TODO: Clean up resources

    logger.log('Graceful shutdown completed');
    process.exit(0);
  };

  process.on('SIGTERM', () => shutdownSignal('SIGTERM'));
  process.on('SIGINT', () => shutdownSignal('SIGINT'));

  // ============================================
  // START SERVER
  // ============================================
  const port = configService.get('PORT', '3000');
  const host = configService.get('HOST', '0.0.0.0');

  await app.listen(port, host);

  logger.log(`🚀 API running on: http://${host}:${port}`);
  logger.log(`📚 Swagger docs: http://${host}:${port}/api/docs`);
  logger.log(`🔒 Health check: http://${host}:${port}/health`);
  logger.log(`⚡ Environment: ${envConfig.NODE_ENV}`);
  logger.log(`🛡️  Security: Helmet + CORS + Rate Limit + JWT Guards`);
}

bootstrap().catch((err) => {
  Logger.error('Failed to start application', err);
  process.exit(1);
});

apps/api/src/config/validation.schema.ts.content:
/**
 * Environment Variables Validation Schema
 * 
 * Uses Zod to validate all environment variables at application startup.
 * Prevents the application from starting with missing or invalid configuration.
 * 
 * @see https://docs.nestjs.com/techniques/configuration
 */

import { z } from 'zod';

/**
 * Environment schema for production-grade validation
 */
export const envSchema = z.object({
  // ============================================
  // NODE ENVIRONMENT
  // ============================================
  NODE_ENV: z
    .enum(['development', 'staging', 'production', 'test'])
    .default('development'),

  // ============================================
  // DATABASE (PostgreSQL)
  // ============================================
  DATABASE_URL: z
    .string()
    .url()
    .startsWith('postgresql://', {
      message: 'DATABASE_URL must be a valid PostgreSQL connection string',
    }),

  // ============================================
  // JWT CONFIGURATION
  // ============================================
  JWT_SECRET: z
    .string()
    .min(32, { message: 'JWT_SECRET must be at least 32 characters' })
    .regex(/^[a-f0-9]{64}$/i, {
      message: 'JWT_SECRET must be a 64-character hex string (32 bytes / 256-bit)',
    }),

  JWT_REFRESH_SECRET: z
    .string()
    .min(32, { message: 'JWT_REFRESH_SECRET must be at least 32 characters' }),

  JWT_ACCESS_EXPIRATION: z
    .string()
    .default('15m'),

  JWT_REFRESH_EXPIRATION: z
    .string()
    .default('7d'),

  // ============================================
  // ENCRYPTION (for sensitive PII)
  // ============================================
  ENCRYPTION_KEY: z
    .string()
    .length(64, {
      message: 'ENCRYPTION_KEY must be exactly 64 characters (32 bytes / 256-bit AES)',
    })
    .regex(/^[a-f0-9]{64}$/i),

  // ============================================
  // REDIS (sessions/cache)
  // ============================================
  REDIS_URL: z
    .string()
    .url()
    .startsWith('redis://', {
      message: 'REDIS_URL must be a valid Redis connection string',
    }),

  // ============================================
  // MINIO / S3 (file storage)
  // ============================================
  MINIO_ENDPOINT: z
    .string()
    .min(1, { message: 'MINIO_ENDPOINT is required' }),

  MINIO_ACCESS_KEY: z
    .string()
    .min(8, { message: 'MINIO_ACCESS_KEY must be at least 8 characters' }),

  MINIO_SECRET_KEY: z
    .string()
    .min(16, { message: 'MINIO_SECRET_KEY must be at least 16 characters' }),

  MINIO_BUCKET: z
    .string()
    .default('escort-media'),

  MINIO_PUBLIC_URL: z
    .string()
    .url()
    .optional(),

  // ============================================
  // API SERVER
  // ============================================
  PORT: z
    .string()
    .default('3000'),

  API_URL: z
    .string()
    .url()
    .optional(),

  FRONTEND_URL: z
    .string()
    .url()
    .default('http://localhost:3001'),

  // ============================================
  // CORS (allowed origins)
  // ============================================
  ALLOWED_ORIGINS: z
    .string()
    .default('http://127.0.0.1:3001'),

  // ============================================
  // RATE LIMITING
  // ============================================
  RATE_LIMIT_TTL: z
    .string()
    .default('60'),

  RATE_LIMIT_MAX: z
    .string()
    .default('100'),

  // ============================================
  // 152-ФЗ COMPLIANCE (Russian data protection)
  // ============================================
  DATA_REGION: z
    .enum(['ru', 'eu', 'global'])
    .default('ru'),

  AUDIT_LOG_RETENTION_DAYS: z
    .string()
    .default('1825'),

  // ============================================
  // EMAIL (SMTP)
  // ============================================
  SMTP_HOST: z
    .string()
    .optional(),

  SMTP_PORT: z
    .string()
    .default('587'),

  SMTP_FROM: z
    .string()
    .email()
    .optional(),

  // ============================================
  // TELEGRAM BOT
  // ============================================
  TELEGRAM_BOT_TOKEN: z
    .string()
    .optional(),

  // ============================================
  // PAYMENT GATEWAYS
  // ============================================
  YOOKASSA_SHOP_ID: z
    .string()
    .optional(),

  YOOKASSA_SECRET_KEY: z
    .string()
    .optional(),

  CRYPTOMUS_API_KEY: z
    .string()
    .optional(),

  CRYPTOMUS_MERCHANT_ID: z
    .string()
    .optional(),
});

/**
 * Type inference from schema
 */
export type EnvConfig = z.infer<typeof envSchema>;

/**
 * Validate environment configuration
 * 
 * @param config - Raw environment variables from process.env
 * @returns Validated and parsed configuration
 * @throws {Error} If validation fails
 * 
 * @example
 * // In main.ts
 * const config = validateEnv(process.env);
 * logger.log(`Running in ${config.NODE_ENV} mode`);
 */
export function validateEnv(config: Record<string, unknown>): EnvConfig {
  const result = envSchema.safeParse(config);

  if (!result.success) {
    console.error('❌ Environment validation failed:');
    console.error('');

    result.error.issues.forEach((issue: any) => {
      const path = issue.path.join('.');
      console.error(`  • ${path}: ${issue.message}`);
    });

    console.error('');
    console.error('Please check your .env file and ensure all required variables are set correctly.');
    console.error('');
    console.error('Quick fix: Copy .env.example to .env and fill in the values:');
    console.error('  cp .env.example .env');
    console.error('');
    console.error('Generate secure secrets:');
    console.error('  # JWT Secret (256-bit)');
    console.error('  openssl rand -hex 32');
    console.error('');
    console.error('  # Encryption Key (256-bit AES)');
    console.error('  openssl rand -hex 32');

    process.exit(1);
  }

  return result.data;
}

/**
 * Get a specific environment variable with type safety
 * 
 * @example
 * const jwtSecret = getEnv('JWT_SECRET');
 * const port = getEnv('PORT', '3000');
 */
export function getEnv<K extends keyof EnvConfig>(
  key: K,
  defaultValue?: EnvConfig[K]
): EnvConfig[K] {
  const value = process.env[key];

  if (value === undefined) {
    if (defaultValue !== undefined) {
      return defaultValue;
    }
    throw new Error(`Required environment variable ${key} is not set`);
  }

  return value as EnvConfig[K];
}

/**
 * Check if running in production
 */
export function isProduction(): boolean {
  return process.env.NODE_ENV === 'production';
}

/**
 * Check if running in development
 */
export function isDevelopment(): boolean {
  return process.env.NODE_ENV === 'development';
}

/**
 * Check if running in test mode
 */
export function isTest(): boolean {
  return process.env.NODE_ENV === 'test';
}

