/**
 * Resolves API base for fetches.
 * - Browser + development → same-origin `/api/...` (Next rewrites → Nest). Avoids CORS and
 *   localhost vs 127.0.0.1 origin mismatches; ignores NEXT_PUBLIC_API_URL in the browser for dev.
 * - Browser + production → NEXT_PUBLIC_API_URL if set, else `/api`.
 * - Server (SSR) → NEXT_PUBLIC_API_URL or direct http://127.0.0.1:3000 in dev.
 */
export function apiUrl(path: string): string {
  const p = path.startsWith('/') ? path : `/${path}`;
  const explicit = process.env.NEXT_PUBLIC_API_URL?.trim().replace(/\/$/, '');

  if (typeof window !== 'undefined') {
    if (process.env.NODE_ENV === 'development') {
      return `/api${p}`;
    }
    if (explicit) return `${explicit}${p}`;
    return `/api${p}`;
  }

  if (explicit) return `${explicit}${p}`;
  return `http://127.0.0.1:3000${p}`;
}

